152→function validateTapParams(params: TapParams): ToolTextResult | null {
153→  const hasX = params.x !== undefined;
154→  const hasY = params.y !== undefined;
155→  const hasSelector = params.id !== undefined || params.label !== undefined;
156→
157→  if (hasX !== hasY) {
158→    return {
159→      content: [{ type: "text", text: "Both x and y must be provided together." }],
160→      isError: true,
161→    };
162→  }
163→
164→  if (hasX && hasSelector) {
165→    return {
166→      content: [{ type: "text", text: "Provide either x/y coordinates or id/label, not both." }],
167→      isError: true,
168→    };
169→  }
170→
171→  if (!hasX && !params.id && !params.label) {
172→    return {
173→      content: [{ type: "text", text: "Provide either x/y coordinates, id, or label." }],
174→      isError: true,
175→    };
176→  }
177→
178→  return null;
179→}
180→
181→function validateTapTabParams(params: TapTabParams): ToolTextResult | null {
182→  if (params.tabCount !== undefined && params.index >= params.tabCount) {
183→    return {
184→      content: [{ type: "text", text: `Tab index ${params.index} is out of range. Valid range: 0..${params.tabCount - 1}` }],
185→      isError: true,
186→    };
187→  }
188→  return null;
189→}
