191→function validateTypeParams(params: TypeParams): ToolTextResult | null {
192→  const modes = [params.text !== undefined, params.stdinText !== undefined, params.file !== undefined].filter(Boolean).length;
193→  if (modes !== 1) {
194→    return {
195→      content: [{ type: "text", text: "Provide exactly one of text, stdinText, or file." }],
196→      isError: true,
197→    };
198→  }
199→  return null;
200→}
201→
202→function buildDescribeArgs(target: string[], params: DescribeParams): string[] {
203→  const args = ["describe-ui", ...target];
204→  pushOption(args, "--output", params.output);
205→  pushOption(args, "--focus-id", params.focusId);
206→  if (params.all) {
207→    args.push("--all");
208→  }
209→  pushOption(args, "--offset", params.offset);
210→  pushOption(args, "--limit", params.limit);
211→  pushOption(args, "--root-element-id", params.rootElementId);
212→  pushOption(args, "--role", params.role);
213→  if (params.visibleOnly) {
214→    args.push("--visible-only");
215→  }
216→  pushOption(args, "--max-depth", params.maxDepth);
217→  if (params.summary) {
218→    args.push("--summary");
219→  }
220→  return args;
221→}
222→
223→function buildSearchArgs(target: string[], params: SearchParams): string[] {
224→  const args = ["search-ui", ...target, "--query", params.query];
225→  pushOption(args, "--role", params.role);
226→  if (params.visibleOnly) {
227→    args.push("--visible-only");
228→  }
229→  pushOption(args, "--max-depth", params.maxDepth);
