252→  const args = ["type"];
253→  if (params.text !== undefined) {
254→    args.push(params.text);
255→  }
256→  if (params.stdinText !== undefined) {
257→    args.push("--stdin");
258→  }
259→  if (params.file !== undefined) {
260→    args.push("--file", params.file);
261→  }
262→  args.push(...target);
263→  return { args, stdinText: params.stdinText };
264→}
