  1→import AppKit
  2→import CoreGraphics
  3→import Foundation
  4→
  5→func handleDescribeUI(_ parsed: ParsedOptions) throws -> Int32 {
  6→    let target = try resolveTarget(from: parsed)
  7→    try ensureAccessibilityTrusted()
  8→    try activateTarget(target)
  9→
 10→    let appRoot = try accessibilityRootElement(for: target)
 11→    var targetRoot = appRoot
 12→
 13→    switch target {
 14→    case .simulator:
 15→        // Default behavior: Focus on in-app content group unless --all is specified
 16→        if !parsed.flags.contains("--all") {
 17→            if let contentGroup = simulatorContentRootElement(from: appRoot) {
 18→                targetRoot = contentGroup
 19→            }
 20→        }
 21→    case .macApp:
 22→        // For macOS apps, start from window level, no iOSContentGroup filtering
 23→        if !parsed.flags.contains("--all") {
 24→            let windows = Children(appRoot)
 25→            if let firstWindow = windows.first {
 26→                targetRoot = firstWindow
 27→            }
 28→        }
 29→    }
 30→
 31→    // Override focus if --focus-id is provided
 32→    if let focusId = parsed.options["--focus-id"] {
 33→        if let found = findAccessibilityElement(in: appRoot, identifier: focusId, label: nil) {
 34→            targetRoot = found
 35→        } else {
 36→            throw NativeError.commandFailed("Could not find element with id: \(focusId)")
 37→        }
 38→    }
 39→
 40→    // Override root if --root-element-id is provided (subtree exploration)
 41→    if let rootElementId = parsed.options["--root-element-id"] {
 42→        if let found = findAccessibilityElement(in: appRoot, identifier: rootElementId, label: nil) {
 43→            targetRoot = found
 44→        } else {
 45→            throw NativeError.commandFailed("Could not find element with id: \(rootElementId)")
 46→        }
 47→    }
 48→
 49→    // Build describe options
 50→    var descOpts = DescribeOptions()
 51→    if let maxDepthStr = parsed.options["--max-depth"], let maxDepthVal = Int(maxDepthStr) {
 52→        descOpts.maxDepth = maxDepthVal
 53→    }
 54→    if let offsetStr = parsed.options["--offset"], let offsetVal = Int(offsetStr) {
 55→        descOpts.offset = offsetVal
 56→    }
 57→    if let limitStr = parsed.options["--limit"], let limitVal = Int(limitStr) {
 58→        descOpts.limit = limitVal
 59→    }
 60→    descOpts.roleFilter = parsed.options["--role"]
 61→    descOpts.summary = parsed.flags.contains("--summary")
 62→    if parsed.flags.contains("--visible-only") {
 63→        descOpts.visibleOnly = true
 64→        if let bounds = windowBounds(for: target) {
 65→            descOpts.screenBounds = bounds
 66→        } else if let mainScreen = NSScreen.main {
 67→            descOpts.screenBounds = mainScreen.frame
 68→        }
 69→    }
 70→
 71→    let lines = describeAccessibilityTree(from: targetRoot, options: descOpts)
 72→    if lines.isEmpty {
 73→        throw NativeError.commandFailed("No accessibility elements found.")
 74→    }
 75→    let report = lines.joined(separator: "\n")
 76→
 77→    if let output = parsed.options["--output"] {
 78→        do {
 79→            try report.write(toFile: output, atomically: true, encoding: .utf8)
 80→            print("UI hierarchy saved to: \(output)")
 81→        } catch {
 82→            throw NativeError.commandFailed("Failed to write hierarchy output: \(error.localizedDescription)")
 83→        }
 84→    }
 85→
 86→    print(report)
 87→    return 0
 88→}
 89→
 90→func handleSearchUI(_ parsed: ParsedOptions) throws -> Int32 {
 91→    let target = try resolveTarget(from: parsed)
 92→    let query = try requiredOption("--query", from: parsed)
 93→    try ensureAccessibilityTrusted()
 94→    try activateTarget(target)
 95→
 96→    let appRoot = try accessibilityRootElement(for: target)
 97→    var searchRoot = appRoot
 98→    if case .simulator = target {
 99→        if let contentGroup = simulatorContentRootElement(from: appRoot) {
100→            searchRoot = contentGroup
101→        }
102→    }
103→
104→    // Build search options
105→    var searchOpts = SearchOptions()
106→    if let maxDepthStr = parsed.options["--max-depth"], let maxDepthVal = Int(maxDepthStr) {
107→        searchOpts.maxDepth = maxDepthVal
108→    }
109→    searchOpts.roleFilter = parsed.options["--role"]
110→    if parsed.flags.contains("--visible-only") {
111→        searchOpts.visibleOnly = true
112→        if let bounds = windowBounds(for: target) {
113→            searchOpts.screenBounds = bounds
114→        } else if let mainScreen = NSScreen.main {
115→            searchOpts.screenBounds = mainScreen.frame
116→        }
117→    }
118→
119→    let results = searchAccessibilityElements(in: searchRoot, query: query, options: searchOpts)
120→    if results.isEmpty {
121→        print("No elements found matching query: \(query)")
122→    } else {
123→        print(results.joined(separator: "\n"))
124→    }
125→    return 0
126→}
127→
128→func handleTap(_ parsed: ParsedOptions) throws -> Int32 {
129→    let target = try resolveTarget(from: parsed)
130→    let accessibilityId = parsed.options["--id"]
131→    let accessibilityLabel = parsed.options["--label"]
132→    let isDouble = parsed.flags.contains("--double")
133→    let includeAll = parsed.flags.contains("--all")
134→    if accessibilityId != nil || accessibilityLabel != nil {
135→        let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
136→        let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
137→
138→        try ensureAccessibilityTrusted()
139→        try activateTarget(target)
140→        if preDelay > 0 {
141→            Thread.sleep(forTimeInterval: preDelay)
142→        }
143→
144→        let root = try accessibilityRootElement(for: target)
145→        let searchRoot: UIElement
146→        if case .simulator = target, !includeAll {
147→            searchRoot = simulatorContentRootElement(from: root) ?? root
148→        } else {
149→            searchRoot = root
150→        }
151→
152→        guard let matchedElement = findAccessibilityElement(
153→            in: searchRoot,
154→            identifier: accessibilityId,
155→            label: accessibilityLabel
156→        ) else {
157→            var selectors: [String] = []
158→            if let accessibilityId {
159→                selectors.append("id='\(accessibilityId)'")
160→            }
161→            if let accessibilityLabel {
162→                selectors.append("label='\(accessibilityLabel)'")
163→            }
